)

// With pagination
NotificationListener<ScrollNotification>(
  onNotification: (scroll) {
    if (scroll.metrics.pixels >= scroll.metrics.maxScrollExtent * 0.8) {
      context.read<ProductBloc>().add(LoadNextPage());
    }
    return false;
  },
  child: listView,
)

